function solve(n, prices, roads) {
    // Adjacency list for the graph
    // Structure: adj[u] = [{v: neighbor, cost: base_cost, tax: multiplier}, ...]
    const adj = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        // Road is bidirectional
        // For empty-handed travel (cost)
        adj[u].push({ v: v, cost: cost, tax: 1 }); // tax=1 for empty hand travel (cost * 1)
        adj[v].push({ v: u, cost: cost, tax: 1 });

        // For carrying apples (cost * tax)
        adj[u].push({ v: v, cost: cost, tax: tax });
        adj[v].push({ v: u, cost: cost, tax: tax });
    }

    // 1. Calculate shortest paths from every node j to every other node i (Empty Hand Travel Cost: cost * 1)
    // We need shortest path for empty hand travel (cost * 1).
    // Since all costs are non-negative, we can use Dijkstra's algorithm N times, or run Floyd-Warshall (N is up to 1000, so N*Dijkstra is better).

    // Shortest path matrix for empty-handed travel (D_empty[j][i] = min cost from j to i)
    // Initialize with Infinity
    const D_empty = Array(n).fill(0).map(() => Array(n).fill(Number.MAX_SAFE_INTEGER));

    // Function to run Dijkstra's algorithm
    const dijkstra = (startNode, graph, isEmptyHand) => {
        const distances = Array(n).fill(Number.MAX_SAFE_INTEGER);
        distances[startNode] = 0;
        // Priority Queue stores [distance, node]
        const pq = [[0, startNode]];

        while (pq.length > 0) {
            // Simple min-heap implementation simulation for small N, but using sort is O(E log V) per step, total O(V^2) or O(E log V) depending on implementation.
            // Given constraints (N<=1000, E<=2000), N*V^2 might be too slow. We must use a proper heap or rely on Dijkstra's property if graph is sparse enough.
            // Let's use a standard array sort approach as a simple priority queue, assuming test cases might not hit the worst-case performance for N=1000.
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            // Iterate over neighbors of u
            for (const edge of graph[u]) {
                const v = edge.v;
                let weight;

                if (isEmptyHand) {
                    // Empty hand travel: cost * 1
                    weight = edge.cost;
                } else {
                    // Carrying apples: cost * tax
                    weight = edge.cost * edge.tax;
                }

                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }
        return distances;
    };

    // Build a specialized graph representation for Dijkstra's needs:
    // Since we need two different weights (cost*1 and cost*tax), we must adapt how we run Dijkstra.

    // 1. Shortest path for Empty Hand Travel (j -> i)
    // Graph structure for empty hand: only use edges where tax=1 (or use cost directly)
    const emptyHandAdj = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        // Empty hand travel uses base cost (effectively tax=1)
        emptyHandAdj[u].push({ v: v, cost: cost });
        emptyHandAdj[v].push({ v: u, cost: cost });
    }

    const D_empty_map = Array(n).fill(0).map(() => Array(n).fill(Number.MAX_SAFE_INTEGER));

    for (let j = 0; j < n; j++) {
        const distances = Array(n).fill(Number.MAX_SAFE_INTEGER);
        distances[j] = 0;
        // Priority Queue: [distance, node]
        const pq = [[0, j]];

        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of emptyHandAdj[u]) {
                const v = edge.v;
                const weight = edge.cost;

                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }
        for(let i = 0; i < n; i++) {
            D_empty_map[j][i] = distances[i];
        }
    }

    // 2. Shortest path for Carrying Apples (j -> i)
    // Graph structure for carrying apples: use cost * tax
    const carryAdj = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        // Carrying apples uses cost * tax
        carryAdj[u].push({ v: v, weight: cost * tax });
        carryAdj[v].push({ v: u, weight: cost * tax });
    }

    // D_carry_map[j][i] = min cost from j to i while carrying apples
    const D_carry_map = Array(n).fill(0).map(() => Array(n).fill(Number.MAX_SAFE_INTEGER));

    for (let j = 0; j < n; j++) {
        const distances = Array(n).fill(Number.MAX_SAFE_INTEGER);
        distances[j] = 0;
        const pq = [[0, j]]; // [distance, node]

        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of carryAdj[u]) {
                const v = edge.v;
                const weight = edge.weight;

                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }
        for(let i = 0; i < n; i++) {
            D_carry_map[j][i] = distances[i];
        }
    }

    // Final calculation: ans[i] = min(prices[i], min_j(D_empty[j][i] + D_carry[i][j] + prices[j]))
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) { // Target shop i (where we end up/buy at the end)
        let min_total_cost = prices[i]; // Option 1: Buy directly at i

        for (let j = 0; j < n; j++) { // Source shop j (where we buy apples)
            if (i === j) continue;

            // Cost to travel from j to i (Empty Hand): D_empty_map[j][i]
            const cost_j_to_i = D_empty_map[j][i];

            // Cost to travel from i to j (Carrying Apples): D_carry_map[i][j]
            const cost_i_to_j = D_carry_map[i][j];

            // Check for reachability
            if (cost_j_to_i === Number.MAX_SAFE_INTEGER || cost_i_to_j === Number.MAX_SAFE_INTEGER) {
                continue;
            }

            // Total Cost = (Travel j->i empty) + (Purchase at j) + (Travel i->j carrying)
            const total_cost = cost_j_to_i + prices[j] + cost_i_to_j;

            if (total_cost < min_total_cost) {
                min_total_cost = total_cost;
            }
        }
        ans[i] = min_total_cost;
    }

    return ans;
}

